import React from 'react'

export default function ProductCard() {
    return (
      <div className="group bg-white rounded-xl p-4 shadow-sm w-[260px] transition-all duration-300 hover:shadow-lg hover:-translate-y-1">
        {/* Badge */}
        <div className="flex justify-between items-start">
          <span className="bg-green-500 text-white text-xs px-3 py-1 rounded-md font-semibold">
            SAVE $59.00
          </span>
          <div className="w-6 h-6 bg-gray-200 rounded-full transition group-hover:bg-gray-300" />
        </div>
  
        {/* Image */}
        <div className="flex justify-center my-4 overflow-hidden">
          <img
            src="https://images.unsplash.com/photo-1587202372775-e229f172b9d7?w=300"
            className="h-20 object-contain transition-transform duration-300 group-hover:scale-110"
          />
        </div>
  
        {/* Divider Count */}
        <div className="text-center text-xs text-gray-400 mb-2">(8)</div>
  
        {/* Title */}
        <h3 className="text-sm font-semibold text-gray-900 leading-snug transition-colors group-hover:text-black">
          uLosk Indica case 2.0, Xenon i10 / 32GB / SSD 512GB / VGA 8GB
        </h3>
  
        {/* Price */}
        <div className="mt-2 flex items-center gap-2">
          <span className="text-red-500 font-bold text-lg">$1,729.00</span>
          <span className="text-gray-400 line-through text-sm">$2,119.00</span>
        </div>
  
        {/* Shipping */}
        <div className="mt-2">
          <span className="bg-green-100 text-green-600 text-xs px-2 py-1 rounded font-semibold">
            FREE SHIPPING
          </span>
        </div>
  
        {/* Stock */}
        <div className="flex items-center gap-2 mt-2 text-sm text-gray-500">
          <span className="text-red-500">●</span>
          Out of stock
        </div>
  
        {/* Buttons */}
        <div className="mt-4 flex gap-2">
          <button className="flex-1 bg-gradient-to-r from-black to-gray-800 text-white text-sm py-2 rounded-md transition-all duration-300 hover:from-gray-900 hover:to-black hover:shadow-md active:scale-95">
            Buy
          </button>
          <button className="flex-1 border border-gray-300 text-sm py-2 rounded-md transition-all duration-300 hover:bg-gray-100 hover:border-gray-400 hover:shadow-sm active:scale-95">
            Add to Cart
          </button>
        </div>
      </div>
    );
  }
  
  